// Solution
var validateRouteParams = function(req, res, next) {
  var url = req.url;
  var regex = /^/users/[a-zA-Z0-9]+/profile/[a-zA-Z0-9]+$/;
  if (regex.test(url)) {
    next();
  } else {
    res.status(404).send('Not Found');
  }
};

